/**
 * Contract Test: Classification Engine Configuration Validation
 *
 * This test MUST FAIL until implementation is complete.
 * Tests the configuration validation system according to OpenAPI specification.
 */

import { ClassificationEngine } from '../../src';
import { ConfigValidationRequest, ConfigValidationResponse, ValidationError } from '../../src/types/api-types';
import { CategoryConfiguration } from '../../src/types/category-configuration';

describe('Classification Engine - Configuration Validation API Contract', () => {
  let engine: ClassificationEngine;

  beforeEach(() => {
    // This will fail - no implementation exists yet
    engine = new ClassificationEngine();
  });

  describe('POST /config/validate', () => {
    it('should validate complete configuration with all pipeline stages', async () => {
      const validConfiguration: CategoryConfiguration = {
        version: '1.0.0',
        lastModified: new Date('2025-09-28T12:00:00Z'),
        hash: 'sha256-abcdef123456789',
        processingConfig: {
          version: 1,
          taxonomyNotes: 'Test configuration for contract validation',
          settings: {
            initialization: {
              applyHardAssertions: true,
              seedCategoryScores: true,
            },
            ruleScoring: {
              useLexicalPatterns: true,
              applySubtypeRules: true,
              boundedAggregation: true,
            },
            attributeProcessing: {
              detectSelfSent: true,
              resolveDomains: true,
              deriveContextFlags: true,
            },
            attributeInfluence: {
              applyBonuses: true,
              applyPenalties: true,
              enforceCaps: true,
            },
            disambiguation: {
              pairwiseAdjustments: true,
              confidenceGapThreshold: 0.1,
            },
            multiLabelSelection: {
              maxLabels: 3,
              minSecondaryConfidence: 0.3,
              allowedCombinations: ['financial+actionable', 'newsletter+informational'],
            },
            aiRouting: {
              highConfidenceThreshold: 0.8,
              aiRequiredThreshold: 0.5,
              skipAiConditions: ['hasHardAssertion', 'confidenceAboveThreshold'],
            },
          },
          categorySignals: {
            financial: {
              hardAssertions: {
                fromDomainsRef: {
                  sourceGroup: 'financialInstitutions',
                  confidence: 'high',
                },
                subjectPrefixes: ['Receipt:', 'Invoice:', 'Payment'],
              },
              strongIndicators: {
                subjectContains: ['payment', 'invoice', 'receipt', 'billing'],
                bodyContains: ['$', 'total:', 'amount due', 'payment method'],
              },
            },
            newsletter: {
              hardAssertions: {
                fromDomainsRef: {
                  sourceGroup: 'newsletterSenders',
                  confidence: 'high',
                },
              },
              strongIndicators: {
                subjectContains: ['newsletter', 'weekly update', 'digest'],
                bodyContains: ['unsubscribe', 'mailing list', 'newsletter'],
              },
            },
          },
          confidenceThresholds: {
            highConfidence: 0.8,
            mediumConfidence: 0.6,
            lowConfidence: 0.4,
            aiClassificationRequired: 0.5,
            manualReviewRequired: 0.3,
            secondaryLabelMinGap: 0.15,
          },
          multiLabelPolicy: {
            maxTopLevelLabels: 2,
            minConfidenceForAdditional: 0.4,
            minDeltaPrimarySecondary: 0.1,
            allowFinancialActionableCopresence: true,
          },
          domainSignalOverrides: {
            financial: {
              hardInclude: ['bank.com', 'paypal.com'],
              hardExclude: ['spam.com'],
              strongInclude: ['finance.com'],
              strongExclude: ['marketing.com'],
            },
          },
          domainSignalResolution: {
            mode: 'runtimeResolved',
            source: 'config/domain-sources.json',
            notes: 'Domain resolution configuration',
          },
          topLevelCategories: {
            financial: {
              description: 'Financial transactions and communications',
              subtypes: {
                receipt: {
                  description: 'Purchase receipts and confirmations',
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        operation: 'containsAny',
                        values: ['receipt', 'purchase confirmation'],
                        weight: 1.0,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: {
                categoryDescription: 'Financial and monetary communications',
                decisionCriteria: ['Contains monetary amounts', 'Related to payments or transactions'],
              },
            },
          },
          attributes: {
            schema: {
              urgency: {
                type: 'enum',
                values: ['low', 'medium', 'high'],
                description: 'Email urgency level',
              },
              selfSent: {
                type: 'boolean',
                description: 'Whether email was sent by the user',
              },
            },
            detectors: [
              {
                attribute: 'urgency',
                field: 'subject',
                operation: 'containsAny',
                values: ['URGENT', 'ASAP', 'IMMEDIATE'],
              },
            ],
            derived: {
              fromFinancialInstitution: {
                logic: 'domainLookup AND attributeMatch',
                notes: 'Derived from domain source and attribute detection',
              },
            },
            attributeBonusMap: {
              financial: {
                hasMoneyAmount: 0.2,
                fromFinancialInstitution: 0.3,
              },
            },
          },
          attributeRelevance: {
            RolesLegend: {
              CORE: 'Essential for category determination',
              PRIMARY_BOOST: 'Strong positive indicator',
              SECONDARY_BOOST: 'Moderate positive indicator',
              DISAMBIGUATOR: 'Helps resolve close decisions',
              FILTER: 'Exclusionary criteria',
              STRUCTURAL: 'Format/structure indicators',
              DERIVED_LINK: 'Links to derived attributes',
              NEUTRAL: 'No impact on scoring',
            },
            financial: {
              categoryRoles: {
                hasMoneyAmount: 'CORE',
                fromFinancialInstitution: 'PRIMARY_BOOST',
                urgency: 'DISAMBIGUATOR',
              },
            },
          },
          aiPrompts: {
            featureExtraction: {
              systemPrompt: ['You are an email analysis expert.'],
              userPrompt: ['Analyze this email for classification features:'],
            },
            finalClassification: {
              systemPrompt: ['You are an email categorization expert.'],
              userPrompt: ['Classify this email into the appropriate category:'],
            },
          },
          featureExtractionSchema: {
            type: 'object',
            properties: {
              category: { type: 'string' },
              confidence: { type: 'number' },
              features: { type: 'array' },
            },
            required: ['category', 'confidence'],
            additionalProperties: false,
          },
        },
        schemaVersion: '1.0.0',
        validationPassed: false, // Will be set by validation
        validationErrors: [],
        compiledRules: [],
        attributeMatrix: {},
      };

      const request: ConfigValidationRequest = {
        configuration: validConfiguration,
        validateAgainstSchema: true,
        generateCompiledRules: true,
      };

      // This MUST fail - no implementation exists
      const response: ConfigValidationResponse = await engine.validateConfig(request);

      // Contract validation for configuration validation
      expect(response).toBeDefined();
      expect(response.valid).toBe(true);
      expect(response.errors).toHaveLength(0);
      expect(response.warnings).toBeDefined();

      // Compiled rules generation
      expect(response.compiledRules).toBeDefined();
      expect(response.compiledRules!.length).toBeGreaterThan(0);
      expect(response.compiledRules![0]).toMatchObject({
        id: expect.any(String),
        category: expect.any(String),
        subtype: expect.any(String),
        tier: expect.stringMatching(/^(high|medium|low)$/),
        pattern: expect.any(Object),
        weight: expect.any(Number),
      });

      // Performance metrics
      expect(response.compilationMetrics).toBeDefined();
      expect(response.compilationMetrics!.compilationDurationMs).toBeGreaterThan(0);
      expect(response.compilationMetrics!.compilationDurationMs).toBeLessThan(5000);
    });

    it('should detect configuration schema violations', async () => {
      const invalidConfiguration = {
        version: '', // Invalid empty version
        processingConfig: {
          // Missing required version field
          settings: {
            initialization: {
              applyHardAssertions: 'invalidBoolean', // Invalid type
            },
          },
          confidenceThresholds: {
            highConfidence: 1.5, // Invalid - exceeds 1.0
            mediumConfidence: -0.1, // Invalid - negative value
          },
        },
      } as unknown as CategoryConfiguration;

      const request: ConfigValidationRequest = {
        configuration: invalidConfiguration,
        validateAgainstSchema: true,
      };

      // This MUST fail - no validation exists yet
      const response = await engine.validateConfig(request);

      expect(response.valid).toBe(false);
      expect(response.errors.length).toBeGreaterThan(0);

      // Should identify specific schema violations
      expect(
        response.errors.some(
          (error: ValidationError) => error.path.includes('version') && error.message.includes('empty')
        )
      ).toBe(true);
      expect(
        response.errors.some((error: ValidationError) =>
          error.path.includes('processingConfig.settings.initialization.applyHardAssertions')
        )
      ).toBe(true);
    });

    it('should validate rule integrity and detect conflicts', async () => {
      const configWithConflictingRules: CategoryConfiguration = {
        version: '1.0.0',
        lastModified: new Date(),
        hash: 'test-hash',
        processingConfig: {
          version: 1,
          taxonomyNotes: 'Test configuration with rule conflicts',
          settings: {
            initialization: { applyHardAssertions: true, seedCategoryScores: true },
            ruleScoring: { useLexicalPatterns: true, applySubtypeRules: true, boundedAggregation: true },
            attributeProcessing: { detectSelfSent: true, resolveDomains: true, deriveContextFlags: true },
            attributeInfluence: { applyBonuses: true, applyPenalties: true, enforceCaps: true },
            disambiguation: { pairwiseAdjustments: true, confidenceGapThreshold: 0.1 },
            multiLabelSelection: { maxLabels: 2, minSecondaryConfidence: 0.3, allowedCombinations: [] },
            aiRouting: { highConfidenceThreshold: 0.8, aiRequiredThreshold: 0.5, skipAiConditions: [] },
          },
          categorySignals: {
            financial: {
              hardAssertions: {
                subjectPrefixes: ['Receipt:'],
              },
              strongIndicators: {
                subjectContains: ['payment'],
              },
            },
            newsletter: {
              hardAssertions: {
                subjectPrefixes: ['Receipt:'], // Conflict: same pattern in different categories
              },
              strongIndicators: {
                subjectContains: ['newsletter'],
              },
            },
          },
          confidenceThresholds: {
            highConfidence: 0.8,
            mediumConfidence: 0.6,
            lowConfidence: 0.4,
            aiClassificationRequired: 0.5,
            manualReviewRequired: 0.3,
            secondaryLabelMinGap: 0.15,
          },
          multiLabelPolicy: {
            maxTopLevelLabels: 2,
            minConfidenceForAdditional: 0.4,
            minDeltaPrimarySecondary: 0.1,
            allowFinancialActionableCopresence: true,
          },
          domainSignalOverrides: {},
          domainSignalResolution: {
            mode: 'runtimeResolved',
            source: 'config/domain-sources.json',
            notes: '',
          },
          topLevelCategories: {},
          attributes: {
            schema: {},
            detectors: [],
            derived: {},
            attributeBonusMap: {},
          },
          attributeRelevance: {
            RolesLegend: {
              CORE: 'Essential for category determination',
              PRIMARY_BOOST: 'Strong positive indicator',
              SECONDARY_BOOST: 'Moderate positive indicator',
              DISAMBIGUATOR: 'Helps resolve close decisions',
              FILTER: 'Exclusionary criteria',
              STRUCTURAL: 'Format/structure indicators',
              DERIVED_LINK: 'Links to derived attributes',
              NEUTRAL: 'No impact on scoring',
            },
          },
          aiPrompts: {
            featureExtraction: { systemPrompt: [], userPrompt: [] },
            finalClassification: { systemPrompt: [], userPrompt: [] },
          },
          featureExtractionSchema: { type: 'object', properties: {}, required: [], additionalProperties: false },
        },
        schemaVersion: '1.0.0',
        validationPassed: false,
        validationErrors: [],
        compiledRules: [],
        attributeMatrix: {},
      };

      const request: ConfigValidationRequest = {
        configuration: configWithConflictingRules,
        validateAgainstSchema: true,
      };

      // This MUST fail - no conflict detection exists yet
      const response = await engine.validateConfig(request);

      expect(response.valid).toBe(false);
      expect(response.errors.length).toBeGreaterThan(0);
      expect(
        response.errors.some(
          (error: ValidationError) => error.message.includes('duplicate') && error.message.includes('Receipt:')
        )
      ).toBe(true);
    });

    it('should validate attribute matrix completeness', async () => {
      const configWithIncompleteMatrix: CategoryConfiguration = {
        version: '1.0.0',
        lastModified: new Date(),
        hash: 'test-hash-matrix',
        processingConfig: {
          version: 1,
          taxonomyNotes: 'Test configuration with incomplete attribute matrix',
          settings: {
            initialization: { applyHardAssertions: true, seedCategoryScores: true },
            ruleScoring: { useLexicalPatterns: true, applySubtypeRules: true, boundedAggregation: true },
            attributeProcessing: { detectSelfSent: true, resolveDomains: true, deriveContextFlags: true },
            attributeInfluence: { applyBonuses: true, applyPenalties: true, enforceCaps: true },
            disambiguation: { pairwiseAdjustments: true, confidenceGapThreshold: 0.1 },
            multiLabelSelection: { maxLabels: 2, minSecondaryConfidence: 0.3, allowedCombinations: [] },
            aiRouting: { highConfidenceThreshold: 0.8, aiRequiredThreshold: 0.5, skipAiConditions: [] },
          },
          categorySignals: {
            financial: { hardAssertions: {}, strongIndicators: {} },
          },
          confidenceThresholds: {
            highConfidence: 0.8,
            mediumConfidence: 0.6,
            lowConfidence: 0.4,
            aiClassificationRequired: 0.5,
            manualReviewRequired: 0.3,
            secondaryLabelMinGap: 0.15,
          },
          multiLabelPolicy: {
            maxTopLevelLabels: 2,
            minConfidenceForAdditional: 0.4,
            minDeltaPrimarySecondary: 0.1,
            allowFinancialActionableCopresence: true,
          },
          domainSignalOverrides: {},
          domainSignalResolution: { mode: 'runtimeResolved', source: '', notes: '' },
          topLevelCategories: {},
          attributes: {
            schema: {
              hasMoneyAmount: { type: 'boolean', description: 'Contains monetary amounts' },
              urgency: { type: 'enum', values: ['low', 'medium', 'high'], description: 'Email urgency' },
            },
            detectors: [],
            derived: {},
            attributeBonusMap: {
              financial: {
                hasMoneyAmount: 0.2,
                // Missing urgency mapping
              },
            },
          },
          attributeRelevance: {
            RolesLegend: {
              CORE: 'Essential for category determination',
              PRIMARY_BOOST: 'Strong positive indicator',
              SECONDARY_BOOST: 'Moderate positive indicator',
              DISAMBIGUATOR: 'Helps resolve close decisions',
              FILTER: 'Exclusionary criteria',
              STRUCTURAL: 'Format/structure indicators',
              DERIVED_LINK: 'Links to derived attributes',
              NEUTRAL: 'No impact on scoring',
            },
            financial: {
              categoryRoles: {
                hasMoneyAmount: 'CORE',
                // Missing urgency role mapping
              },
            },
          },
          aiPrompts: {
            featureExtraction: { systemPrompt: [], userPrompt: [] },
            finalClassification: { systemPrompt: [], userPrompt: [] },
          },
          featureExtractionSchema: { type: 'object', properties: {}, required: [], additionalProperties: false },
        },
        schemaVersion: '1.0.0',
        validationPassed: false,
        validationErrors: [],
        compiledRules: [],
        attributeMatrix: {},
      };

      const request: ConfigValidationRequest = {
        configuration: configWithIncompleteMatrix,
        validateAgainstSchema: true,
      };

      // This MUST fail - no matrix validation exists yet
      const response = await engine.validateConfig(request);

      expect(response.valid).toBe(false);
      expect(response.errors.length).toBeGreaterThan(0);
      expect(
        response.errors.some(
          (error: ValidationError) => error.message.includes('urgency') || error.path.includes('urgency')
        )
      ).toBe(true);
    });

    it('should generate optimized compiled rules', async () => {
      const validConfig: CategoryConfiguration = {
        version: '1.0.0',
        lastModified: new Date(),
        hash: 'compiled-rules-test',
        processingConfig: {
          version: 1,
          taxonomyNotes: 'Test configuration for rule compilation',
          settings: {
            initialization: { applyHardAssertions: true, seedCategoryScores: true },
            ruleScoring: { useLexicalPatterns: true, applySubtypeRules: true, boundedAggregation: true },
            attributeProcessing: { detectSelfSent: true, resolveDomains: true, deriveContextFlags: true },
            attributeInfluence: { applyBonuses: true, applyPenalties: true, enforceCaps: true },
            disambiguation: { pairwiseAdjustments: true, confidenceGapThreshold: 0.1 },
            multiLabelSelection: { maxLabels: 2, minSecondaryConfidence: 0.3, allowedCombinations: [] },
            aiRouting: { highConfidenceThreshold: 0.8, aiRequiredThreshold: 0.5, skipAiConditions: [] },
          },
          categorySignals: {},
          confidenceThresholds: {
            highConfidence: 0.8,
            mediumConfidence: 0.6,
            lowConfidence: 0.4,
            aiClassificationRequired: 0.5,
            manualReviewRequired: 0.3,
            secondaryLabelMinGap: 0.15,
          },
          multiLabelPolicy: {
            maxTopLevelLabels: 2,
            minConfidenceForAdditional: 0.4,
            minDeltaPrimarySecondary: 0.1,
            allowFinancialActionableCopresence: true,
          },
          domainSignalOverrides: {},
          domainSignalResolution: { mode: 'runtimeResolved', source: '', notes: '' },
          topLevelCategories: {
            financial: {
              description: 'Financial communications',
              subtypes: {
                receipt: {
                  description: 'Purchase receipts',
                  ruleBasedClassification: {
                    highConfidence: [
                      {
                        field: 'subject',
                        operation: 'regexAny',
                        values: ['^Receipt:', '\\bOrder\\s+#\\d+'],
                        weight: 1.0,
                      },
                    ],
                  },
                },
              },
              aiFinalClassification: { categoryDescription: '', decisionCriteria: [] },
            },
          },
          attributes: { schema: {}, detectors: [], derived: {}, attributeBonusMap: {} },
          attributeRelevance: {
            RolesLegend: {
              CORE: 'Essential for category determination',
              PRIMARY_BOOST: 'Strong positive indicator',
              SECONDARY_BOOST: 'Moderate positive indicator',
              DISAMBIGUATOR: 'Helps resolve close decisions',
              FILTER: 'Exclusionary criteria',
              STRUCTURAL: 'Format/structure indicators',
              DERIVED_LINK: 'Links to derived attributes',
              NEUTRAL: 'No impact on scoring',
            },
          },
          aiPrompts: {
            featureExtraction: { systemPrompt: [], userPrompt: [] },
            finalClassification: { systemPrompt: [], userPrompt: [] },
          },
          featureExtractionSchema: { type: 'object', properties: {}, required: [], additionalProperties: false },
        },
        schemaVersion: '1.0.0',
        validationPassed: false,
        validationErrors: [],
        compiledRules: [],
        attributeMatrix: {},
      };

      const request: ConfigValidationRequest = {
        configuration: validConfig,
        generateCompiledRules: true,
      };

      // This MUST fail - no rule compilation exists yet
      const response = await engine.validateConfig(request);

      expect(response.valid).toBe(true);
      expect(response.compiledRules!.length).toBeGreaterThan(0);

      // Validate compiled rule structure
      const compiledRule = response.compiledRules![0];
      expect(compiledRule.category).toBe('financial');
      expect(compiledRule.subtype).toBe('receipt');
      expect(compiledRule.tier).toBe('high');
      expect(compiledRule.pattern).toBeInstanceOf(RegExp);
      expect(compiledRule.weight).toBe(1.0);

      // Performance optimization validation
      expect(response.compilationMetrics).toBeDefined();
      expect(response.compilationMetrics!.rulesGenerated).toBe(response.compiledRules!.length);
      expect(response.compilationMetrics!.optimizationsApplied).toBeGreaterThanOrEqual(0);
      expect(response.compilationMetrics!.compilationDurationMs).toBeGreaterThan(0);
    });

    it('should handle malformed configuration gracefully', async () => {
      const malformedConfig = {
        // Completely invalid structure
        invalid: 'configuration',
      } as unknown as CategoryConfiguration;

      const request: ConfigValidationRequest = {
        configuration: malformedConfig,
        validateAgainstSchema: true,
      };

      // This MUST fail - no error handling exists yet
      await expect(engine.validateConfig(request)).rejects.toThrow('Malformed configuration');
    });
  });
});

