      expect(response.results[0].primaryCategory).toMatch(/newsletter|informational/i);
      expect(response.performanceMetrics.parallelStagesCount).toBe(0); // Sequential mode
    });

    it('should validate batch size limits', async () => {
      const emails = Array.from({ length: 101 }, (_, i) => ({
        id: `test-email-${i}`,
        threadId: `thread-${i}`,
        subject: `Test Email ${i}`,
        from: {
          email: 'test@example.com',
          name: 'Test Sender',
          raw: 'Test Sender <test@example.com>',
        },
        to: [
          {
            email: 'user@example.com',
            name: 'Test User',
            raw: 'Test User <user@example.com>',
          },
        ],
        date: new Date(),
        bodyPlain: `Test email content ${i}`,
        headers: [],
      }));

      const request: BatchClassificationRequest = {
        emails,
        sessionId: '789e0123-e89b-12d3-a456-426614174002',
        processingMode: 'parallel',
      };

      // This MUST fail - no validation exists yet
      await expect(engine.classifyBatch(request)).rejects.toThrow('Batch size exceeds maximum of 100 emails');
    });

    it('should handle invalid email content gracefully', async () => {
      const request: BatchClassificationRequest = {
        emails: [
          {
            id: '',
            threadId: '',
            subject: '',
            from: {
              email: 'invalid-email',
              name: '',
              raw: '',
