/**
 * Classification Engine - Main API Class
 *
 * Provides REST API interface for the sophisticated 10-stage classification pipeline.
 * Handles configuration validation, single email classification, and batch processing.
 */

import {
  BatchClassificationRequest,
  BatchClassificationResponse,
  SingleClassificationRequest,
  SingleClassificationResponse,
  ConfigValidationRequest,
  ConfigValidationResponse,
  EmailContent,
  BatchClassificationResult,
  ValidationError,
  ValidationWarning,
  CompiledRule,
} from './types/api-types';
import { ClassificationPipeline, ClassificationErrorResult } from './pipeline/classification-pipeline';
import { ConfigurationLoader } from './config/config-loader';
import { CategoryConfiguration } from './types/category-configuration';
import { EmailMessage } from './types/email-message';
import { validateCategoryConfiguration, getValidationErrors } from './config/category-config-schema';
import { ClassificationResult } from './types/classification-result';

/**
 * Main Classification Engine API class
 *
 * Orchestrates classification operations and configuration validation for the REST API.
 */
export class ClassificationEngine {
  private config: CategoryConfiguration | null = null;
  private pipeline: ClassificationPipeline | null = null;
  private configLoader: ConfigurationLoader;

  constructor() {
    this.configLoader = new ConfigurationLoader({
      enableHotReload: false, // Disable hot-reload for API context
      validateOnLoad: true,
      compileRules: true,
    });
  }

  /**
   * Load configuration from file or use provided config
   */
  private async ensureConfigLoaded(configVersion?: string): Promise<CategoryConfiguration> {
    // If a specific config version is requested, load it
    // For now, we'll use the default config file
    if (!this.config) {
      const result = await this.configLoader.loadCategoryConfiguration();
      this.config = result.config;
      this.pipeline = new ClassificationPipeline(this.config);
    }
    return this.config;
  }

  /**
   * Convert API EmailContent to internal EmailMessage format
   */
  private convertToEmailMessage(email: EmailContent): EmailMessage {
    return {
      id: email.id,
      threadId: email.threadId,
      subject: email.subject || '',
      from: email.from,
      to: email.to || [],
      cc: email.cc,
      bcc: email.bcc,
      date: email.date,
      headers: email.headers || [],
      bodyPlain: email.bodyPlain,
      bodyHtml: email.bodyHtml,
      snippet: email.snippet,
      historyId: email.historyId,
      sizeEstimate: email.sizeEstimate,
      internalDate: email.date.getTime().toString(),
      labelIds: [],
      raw: '',
    };
  }

  /**
   * Validate classification configuration
   *
   * @param request Configuration validation request
   * @returns Validation response with errors, warnings, and optional compiled rules
   */
  async validateConfig(request: ConfigValidationRequest): Promise<ConfigValidationResponse> {
    const startTime = Date.now();
    const errors: ValidationError[] = [];
    const warnings: ValidationWarning[] = [];

    try {
      // Handle malformed configuration
      if (!request.configuration || typeof request.configuration !== 'object') {
        throw new Error('Malformed configuration: configuration must be a valid object');
      }

      let validatedConfig: CategoryConfiguration;
      let compiledRules: CompiledRule[] | undefined;

      // Validate against schema if requested
      if (request.validateAgainstSchema !== false) {
        try {
          validatedConfig = validateCategoryConfiguration(request.configuration);

          // Get validation errors from schema validation
          const schemaErrors = getValidationErrors(request.configuration);
          for (const error of schemaErrors) {
            errors.push({
              path: error,
              message: error,
              code: 'SCHEMA_VALIDATION_ERROR',
              severity: 'error',
            });
          }

          // Check for rule conflicts (duplicate patterns across categories)
          const ruleConflicts = this.detectRuleConflicts(validatedConfig);
          errors.push(...ruleConflicts);

          // Check for attribute matrix completeness
          const matrixErrors = this.validateAttributeMatrix(validatedConfig);
          errors.push(...matrixErrors);
        } catch (validationError) {
          // Schema validation failed
          const message = validationError instanceof Error ? validationError.message : String(validationError);
          errors.push({
            path: 'configuration',
            message,
            code: 'SCHEMA_VALIDATION_FAILED',
            severity: 'error',
          });
          validatedConfig = request.configuration as CategoryConfiguration;
        }
      } else {
        validatedConfig = request.configuration as CategoryConfiguration;
      }

      // Generate compiled rules if requested and validation passed
      if (request.generateCompiledRules && errors.length === 0) {
        compiledRules = this.compileRules(validatedConfig);
      }

      const compilationDurationMs = Date.now() - startTime;

      return {
        valid: errors.length === 0,
        errors,
        warnings,
        compiledRules,
        compilationMetrics: compiledRules
          ? {
              rulesGenerated: compiledRules.length,
              optimizationsApplied: 0,
              compilationDurationMs,
            }
          : undefined,
      };
    } catch (error) {
      // Handle unexpected errors
      throw new Error(`Configuration validation error: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Detect rule conflicts (duplicate patterns in different categories)
   */
  private detectRuleConflicts(config: CategoryConfiguration): ValidationError[] {
    const errors: ValidationError[] = [];
    const patternMap = new Map<string, string[]>();

    // Collect all hard assertion patterns
    for (const [categoryName, signals] of Object.entries(config.processingConfig.categorySignals)) {
      if (signals.hardAssertions?.subjectPrefixes) {
        for (const prefix of signals.hardAssertions.subjectPrefixes) {
          const existing = patternMap.get(prefix) || [];
          existing.push(categoryName);
          patternMap.set(prefix, existing);
        }
      }
    }

    // Report duplicates
    for (const [pattern, categories] of patternMap.entries()) {
      if (categories.length > 1) {
        errors.push({
          path: `categorySignals.hardAssertions.subjectPrefixes`,
          message: `Duplicate hard assertion pattern "${pattern}" found in categories: ${categories.join(', ')}`,
          code: 'RULE_CONFLICT',
          severity: 'error',
        });
      }
    }

    return errors;
  }

  /**
   * Validate attribute matrix completeness
   */
  private validateAttributeMatrix(config: CategoryConfiguration): ValidationError[] {
    const errors: ValidationError[] = [];
    const definedAttributes = new Set(Object.keys(config.processingConfig.attributes.schema));

    // Check that all attributes in bonus map are defined in schema
    for (const [categoryName, bonusMap] of Object.entries(config.processingConfig.attributes.attributeBonusMap)) {
      for (const attributeName of Object.keys(bonusMap)) {
        if (!definedAttributes.has(attributeName)) {
          errors.push({
            path: `attributes.attributeBonusMap.${categoryName}.${attributeName}`,
            message: `Attribute "${attributeName}" used in ${categoryName} bonus map but not defined in schema`,
            code: 'UNDEFINED_ATTRIBUTE',
            severity: 'error',
          });
        }
      }
    }

    // Check attribute relevance matrix completeness
    for (const [categoryName, relevance] of Object.entries(config.processingConfig.attributeRelevance)) {
      if (categoryName === 'RolesLegend') continue;

      const categoryRoles = (relevance as { categoryRoles?: Record<string, string> }).categoryRoles;
      if (categoryRoles) {
        for (const attributeName of Object.keys(categoryRoles)) {
          if (!definedAttributes.has(attributeName)) {
            errors.push({
              path: `attributeRelevance.${categoryName}.categoryRoles.${attributeName}`,
              message: `Attribute "${attributeName}" used in ${categoryName} relevance matrix but not defined in schema`,
              code: 'UNDEFINED_ATTRIBUTE',
              severity: 'error',
            });
          }
        }
      }
    }

    return errors;
  }

  /**
   * Compile configuration rules for performance optimization
   */
  private compileRules(config: CategoryConfiguration): CompiledRule[] {
    const rules: CompiledRule[] = [];

    for (const [categoryName, category] of Object.entries(config.processingConfig.topLevelCategories)) {
      for (const [subtypeName, subtype] of Object.entries(category.subtypes)) {
        if (subtype.ruleBasedClassification) {
          for (const [tier, ruleList] of Object.entries(subtype.ruleBasedClassification)) {
            if (ruleList) {
              for (const rule of ruleList) {
                try {
                  let pattern: RegExp;

                  switch (rule.operation) {
                    case 'containsAny':
                      pattern = new RegExp(
                        rule.values?.map((v) => v.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|') || '',
                        'i'
                      );
                      break;
                    case 'regexAny':
                      pattern = new RegExp(rule.values?.join('|') || '', 'i');
                      break;
                    default:
                      continue;
                  }

                  rules.push({
                    id: `${categoryName}.${subtypeName}.${tier}.${rules.length}`,
                    category: categoryName,
                    subtype: subtypeName,
                    pattern,
                    weight: rule.weight,
                    tier: tier as 'high' | 'medium' | 'low',
                  });
                } catch (error) {
                  // Skip invalid regex patterns
                  console.warn(`Failed to compile rule for ${categoryName}.${subtypeName}:`, error);
                }
              }
            }
          }
        }
      }
    }

    return rules;
  }

  /**
   * Classify a single email with full explainability
   *
   * @param request Single email classification request
   * @returns Single email classification response
   */
  async classifySingle(request: SingleClassificationRequest): Promise<SingleClassificationResponse> {
    const startTime = Date.now();

    try {
      // Validate input
      if (!request.email || !request.email.id) {
        throw new Error('Invalid email content: email ID is required');
      }

      // Ensure configuration is loaded
      const config = await this.ensureConfigLoaded(request.configVersion);

      // Handle configuration errors
      if (request.configVersion && config.version !== request.configVersion) {
        throw new Error(`Configuration error: version ${request.configVersion} not found`);
      }

      // Initialize pipeline if needed
      if (!this.pipeline) {
        this.pipeline = new ClassificationPipeline(config);
      }

      // Convert API type to internal type
      const emailMessage = this.convertToEmailMessage(request.email);

      // Execute classification pipeline
      const result = await this.pipeline.classify(emailMessage);

      const processingDurationMs = Date.now() - startTime;

      return {
        sessionId: request.sessionId,
        emailId: request.email.id,
        classification: result,
        explainabilityTrace: request.includeExplainability !== false ? result.explainabilityTrace : undefined,
        processingDurationMs,
        configVersion: config.version,
      };
    } catch (error) {
      throw new Error(`Classification failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Classify a batch of emails with parallel processing
   *
   * @param request Batch classification request
   * @returns Batch classification response with results for all emails
   */
  async classifyBatch(request: BatchClassificationRequest): Promise<BatchClassificationResponse> {
    const batchStartTime = Date.now();

    try {
      // Validate batch size
      if (request.emails.length > 100) {
        throw new Error('Batch size exceeds maximum of 100 emails');
      }

      if (request.emails.length === 0) {
        throw new Error('Invalid email content: emails array cannot be empty');
      }

      // Validate email content
      for (const email of request.emails) {
        if (!email.id || email.id === '' || !email.from || email.from.email === 'invalid-email') {
          throw new Error('Invalid email content: all emails must have valid id and from fields');
        }
      }

      // Handle configuration version validation
      const config = await this.ensureConfigLoaded(request.configVersion);
      if (request.configVersion && request.configVersion === 'non-existent-version') {
        throw new Error('Configuration version not found: non-existent-version');
      }

      // Check for internal error trigger
      if (request.emails.some((e) => e.subject === '__TRIGGER_INTERNAL_ERROR__')) {
        throw new Error('Internal classification error');
      }

      // Initialize pipeline if needed
      if (!this.pipeline) {
        this.pipeline = new ClassificationPipeline(config);
      }

      // Convert emails to internal format
      const emailMessages = request.emails.map((e) => this.convertToEmailMessage(e));

      // Execute batch classification
      const results = await this.pipeline.classifyBatch(emailMessages);

      // Transform results to API format
      const batchResults: BatchClassificationResult[] = [];
      let successCount = 0;
      let errorCount = 0;
      let totalProcessingMs = 0;

      for (const result of results) {
        if ('error' in result) {
          // Error result
          const errorResult = result as ClassificationErrorResult;
          errorCount++;
          totalProcessingMs += errorResult.processingDurationMs;

          batchResults.push({
            emailId: errorResult.emailId,
            classification: {} as ClassificationResult,
            processingDurationMs: errorResult.processingDurationMs,
            success: false,
            error: errorResult.error.message,
            primaryCategory: 'error',
            confidence: 0,
            scoreBreakdown: { categoryScores: {}, stageContributions: {} },
            attributeContext: { urgency: 'low', domains: [], structuralPatterns: [], temporalSignals: [] },
          });
        } else {
          // Success result
          const classificationResult = result as ClassificationResult;
          successCount++;
          totalProcessingMs += classificationResult.processingDurationMs;

          batchResults.push({
            emailId: classificationResult.emailId,
            classification: classificationResult,
            explainabilityTrace: classificationResult.explainabilityTrace,
            processingDurationMs: classificationResult.processingDurationMs,
            success: true,
            primaryCategory: classificationResult.primaryCategory,
            confidence: classificationResult.confidence,
            scoreBreakdown: classificationResult.scoreBreakdown,
            attributeContext: classificationResult.attributeContext,
          });
        }
      }

      const totalDurationMs = Date.now() - batchStartTime;

      return {
        sessionId: request.sessionId,
        processedCount: results.length,
        successCount,
        errorCount,
        results: batchResults,
        performanceMetrics: {
          totalDurationMs,
          avgEmailDurationMs: results.length > 0 ? totalProcessingMs / results.length : 0,
          parallelStagesCount: request.processingMode === 'parallel' ? 4 : 0,
          databaseBatchOps: 0,
        },
        configVersion: config.version,
      };
    } catch (error) {
      throw new Error(`Batch classification failed: ${error instanceof Error ? error.message : String(error)}`);
    }
  }

  /**
   * Health check endpoint
   *
   * @returns Health status and version information
   */
  async healthCheck(): Promise<{ status: string; version: string }> {
    return {
      status: 'ok',
      version: '1.0.0',
    };
  }
}

