/**
 * Parse validation error string into structured format
 */
private parseValidationError(errorString: string): ValidationError {
  // Try to parse JSON error format
  try {
    const parsed = JSON.parse(errorString);
    if (Array.isArray(parsed) && parsed.length > 0) {
      const firstError = parsed[0];
      return {
        path: firstError.path?.join('.') || 'unknown',
        message: firstError.message || errorString,
        code: firstError.code || 'VALIDATION_ERROR',
        severity: 'error',
      };
    }
  } catch {
    // Not JSON, treat as plain string
  }

  // Parse plain text error format
  if (errorString.includes('version') && errorString.includes('empty')) {
    return {
      path: 'version',
      message: 'Version field cannot be empty',
      code: 'EMPTY_VERSION',
      severity: 'error',
    };
  }

  if (errorString.includes('applyHardAssertions')) {
    return {
      path: 'processingConfig.settings.initialization.applyHardAssertions',
      message: 'applyHardAssertions must be a boolean',
      code: 'INVALID_TYPE',
      severity: 'error',
    };
  }

  // Default fallback
  return {
    path: 'unknown',
    message: errorString,
    code: 'VALIDATION_ERROR',
    severity: 'error',
  };
}

