    31→ * Orchestrates classification operations and configuration validation for the REST API.
    32→ */
    33→export class ClassificationEngine {
    34→  private config: CategoryConfiguration | null = null;
    35→  private pipeline: ClassificationPipeline | null = null;
    36→  private configLoader: ConfigurationLoader;
    37→
    38→  constructor(configDir?: string) {
    39→    // Default to project root config directory (two levels up from package)
    40→    // FIXME this should auto-detect and find the config directory
    41→    const defaultConfigDir = configDir || '/workspaces/gmail-automation/config';
    42→
    43→    this.configLoader = new ConfigurationLoader({
