    55→    // If a specific config version is requested, load it
    56→    // For now, we'll use the default config file
    57→    if (!this.config) {
    58→      const result = await this.configLoader.loadCategoryConfiguration();
    59→      this.config = result.config;
    60→      this.pipeline = new ClassificationPipeline(this.config);
    61→    }
    62→    return this.config;
    63→  }
    64→
    65→  /**
    66→   * Convert API EmailContent to internal EmailMessage format
    67→   */
