    69→    return {
    70→      id: email.id,
    71→      threadId: email.threadId,
    72→      subject: email.subject || '',
    73→      from: email.from,
    74→      to: email.to || [],
    75→      cc: email.cc,
    76→      bcc: email.bcc,
    77→      date: email.date,
    78→      headers: email.headers || [],
    79→      bodyPlain: email.bodyPlain,
    80→      bodyHtml: email.bodyHtml,
    81→      snippet: email.snippet,
    82→      historyId: email.historyId,
    83→      sizeEstimate: email.sizeEstimate,
    84→      internalDate: email.date.getTime().toString(),
    85→      labelIds: [],
    86→      raw: '',
    87→    };
    88→  }
    89→
    90→  /**
