    96→  async validateConfig(request: ConfigValidationRequest): Promise<ConfigValidationResponse> {
    97→    const startTime = Date.now();
    98→    const errors: ValidationError[] = [];
    99→    const warnings: ValidationWarning[] = [];
   100→
   101→    try {
