   122→          const schemaErrors = getValidationErrors(request.configuration);
   123→          if (schemaErrors.length > 0) {
   124→            // Parse each error into structured ValidationError format
   125→            for (const error of schemaErrors) {
   126→              const parsedError = this.parseValidationError(error);
   127→              errors.push(parsedError);
   128→            }
   129→          }
